#!/usr/bin/env python3
import numpy as np


class Reward:
    def __init__(self, max_height, max_side):
        self.max_height = max_height
        self.max_side = max_side

    def get_reward(self, obs, norm_obs, action, landed, eps_pos_xy, eps_vel_xy):
        done = False
        reward = 0.0

        # STATES
        dist_xy = np.linalg.norm(obs[:2])
        z = abs(obs[2])
        vel = np.linalg.norm(obs[3:6])

        # MAIN OBJECTIVE
        reward -= 2.0 * dist_xy
        reward -= 1.5 * z
        reward -= 0.5 * vel
        reward += 1.0 / (1.0 + dist_xy)

        # ACTION PENALTY
        reward -= 0.1 * np.linalg.norm(action)

        # SUCCESS
        if landed and dist_xy < eps_pos_xy:
            if vel < eps_vel_xy:
                print("Perfect landing")
                reward += 150.0
            else:
                print("Hard landing")
                reward += 50.0
            done = True

        # WRONG LANDING
        elif landed and dist_xy > eps_pos_xy:
            print("Wrong landing")
            reward -= 100.0
            done = True

        # OUT OF BOUNDS
        elif z > self.max_height or abs(obs[0]) > self.max_side or abs(obs[1]) > self.max_side:
            print("Out of bounds")
            reward -= 100.0
            done = True

        # CLOSE BONUS
        if dist_xy < 0.3:
            reward += 5.0

        # FAST NEAR GROUND PENALTY
        if z < 0.5 and vel > 0.5:
            reward -= 10.0

        return reward, done
